using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Register the trainer and train the model at startup
builder.Services.AddSingleton<ModelTrainerService>();

var app = builder.Build();

// Train and evaluate the model before accepting requests
var trainer = app.Services.GetRequiredService<ModelTrainerService>();
trainer.TrainAndEvaluate();

// Register the pooled prediction engine (thread-safe for ASP.NET Core)
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild the service provider to include the prediction pool
app = builder.Build();

app.MapControllers();
app.Run();

