using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainerService>();

// Train the model eagerly so the .zip file exists before the pool needs it
var trainer = new ModelTrainerService(
    LoggerFactory.Create(b => b.AddConsole()).CreateLogger<ModelTrainerService>());
trainer.TrainAndEvaluate();

// Thread-safe prediction engine pool (never use a singleton PredictionEngine)
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

